import hashlib, struct, redis
from openai import OpenAI
from typing import Generator

openai_client = OpenAI()
redis_client = redis.Redis(host="redis-prod", port=6379, db=1, decode_responses=False)

MODEL = "text-embedding-3-small"
TTL = 60 * 60 * 24 * 60  # 60 days — contracts rarely add new clause types

def _key(text: str) -> str:
    norm = " ".join(text.lower().split())  # lowercase for legal text normalisation
    return "leg:emb:" + hashlib.sha256(f"{MODEL}:{norm}".encode()).hexdigest()

def _pack(vec: list[float]) -> bytes:
    return struct.pack(f"<{len(vec)}f", *vec)

def _unpack(raw: bytes) -> list[float]:
    return list(struct.unpack(f"<{len(raw)//4}f", raw))

def embed_clause(clause: str) -> list[float]:
    k = _key(clause)
    if hit := redis_client.get(k):
        return _unpack(hit)
    vec = openai_client.embeddings.create(input=clause, model=MODEL).data[0].embedding
    redis_client.setex(k, TTL, _pack(vec))
    return vec

def analyse_contract(clauses: list[str]) -> list[dict]:
    """Embed each clause with cache; retrieve top-3 precedents per clause."""
    results = []
    for clause in clauses:
        vec = embed_clause(clause)
        # ... vector store similarity search with vec ...
        results.append({"clause": clause[:80], "vec_dim": len(vec)})
    return results

# Simulate a contract with 10 clauses (some repeated boilerplate)
clauses = [
    "Governing Law. This agreement shall be governed by the laws of Delaware.",
    "Indemnification. Each party shall indemnify the other against third-party claims.",
    "Governing Law. This agreement shall be governed by the laws of Delaware.",  # duplicate
    "Limitation of Liability. In no event shall either party be liable for indirect damages.",
    "Indemnification. Each party shall indemnify the other against third-party claims.",  # duplicate
]
print(analyse_contract(clauses))
# Clauses 3 and 5 above are served from Redis cache without any API call.
